  name: string                     // "User", "Post", etc.
  dbName: string | null            // Database table name
  schema: string | null            // Schema/namespace
  fields: DMMF.Field[]            // Model fields
  uniqueFields: string[][]         // Unique constraint field combinations
  uniqueIndexes: { name: string; fields: string[] }[]
  documentation?: string           // JSDoc comments
  primaryKey: { name: string | null; fields: string[] } | null
  isGenerated?: boolean
}
```

#### **DMMF.Field** (individual field in a model)
```typescript
{
  kind: 'scalar' | 'object' | 'enum' | 'unsupported'
  name: string
  type: string  // "String", "Int", "Boolean", "DateTime", "JSON", "Bytes", "Decimal", "BigInt", etc.

  // Modifiers
  isRequired: boolean        // Not optional (!= in schema)
  isList: boolean           // Array type ([] in schema)
  isUnique: boolean         // @unique
  isId: boolean             // @id
  isReadOnly: boolean       // @readonly
  isGenerated?: boolean     // @default(uuid()), @default(now())
  isUpdatedAt?: boolean     // @updatedAt

  // Relations
  relationName?: string
  relationFromFields?: string[]  // Foreign key fields
  relationToFields?: string[]    // Referenced fields
  relationOnDelete?: string      // Cascade, etc.
  relationOnUpdate?: string

  // Database
  dbName?: string | null         // Database column name
  nativeType?: [string, string[]] | null  // e.g., ['VarChar', ['191']]

  // Defaults
  hasDefaultValue: boolean
  default?: FieldDefault | FieldDefaultScalar | FieldDefaultScalar[]

  // Documentation
  documentation?: string
}
```

#### **DMMF.DatamodelEnum** (enum definition)
```typescript
{
  name: string
  values: { name: string; dbName: string | null }[]
  dbName?: string | null
  documentation?: string
}
```

---

### 2. Field Type Mapping to TypeScript

**File:** `/packages/client-generator-ts/src/utils/common.ts`

DMMF field types map to TypeScript types like this:

```typescript
const GraphQLScalarToJSTypeTable = {
  String: 'string',
  Int: 'number',
  Float: 'number',
  Boolean: 'boolean',
  Long: 'number',
  DateTime: ['Date', 'string'],           // Can be Date or string
  ID: 'string',
  UUID: 'string',
  Json: 'runtime.JsonValue',              // Special
  Bytes: 'runtime.Bytes',                 // Special
  Decimal: ['runtime.Decimal', 'runtime.DecimalJsLike', 'number', 'string'],  // Union type
  BigInt: ['bigint', 'number'],           // Union type
}
```

**Logic for converting a field to TypeScript:**
1. Look up `field.type` in the mapping table
2. If it's an object type (relation), create a named type for the related model
3. If it's an enum, reference it as `$Enums.EnumName`
4. If `field.isList` is true, wrap in array: `Type[]`
5. If `field.isRequired` is false, add null: `Type | null`

Example from the codebase (Output.ts):
```typescript
function buildModelOutputProperty(field: DMMF.Field, dmmf) {
  let fieldTypeName = GraphQLScalarToJSTypeTable[field.type] || field.type

  let fieldType: ts.TypeBuilder
  if (field.kind === 'object') {
    fieldType = ts.namedType(getPayloadName(field.type))  // Relation
  } else if (field.kind === 'enum') {
    fieldType = ts.namedType(`$Enums.${fieldTypeName}`)
  } else {
    fieldType = ts.namedType(fieldTypeName)
  }

  if (field.isList) {
    fieldType = ts.array(fieldType)
  } else if (!field.isRequired) {
    fieldType = ts.unionType(fieldType).addVariant(ts.nullType)
  }

  return ts.property(field.name, fieldType)
}
```

---

### 3. @prisma/ts-builders - TypeScript Code Generation

**Files:** `/packages/ts-builders/src/`

This is a fluent builder API for generating TypeScript code. Key classes:

#### **File** (top-level file container)
```typescript
const file = ts.file()
  .addImport(ts.moduleImport('some-module').named('Thing'))
  .add(ts.interfaceDeclaration('User'))
```

#### **Interface**
```typescript
const userInterface = ts.interfaceDeclaration('User')
  .add(ts.property('id', ts.stringType))
  .add(ts.property('name', ts.stringType))
  .add(ts.property('email', ts.stringType).optional())
  .extends(ts.namedType('BaseEntity'))

// Result:
// interface User extends BaseEntity {
//   id: string
//   name: string
//   email?: string
// }
```

#### **Class**
```typescript
const myClass = ts.classDeclaration('User')
  .add(ts.property('id', ts.stringType).readonly())
  .add(ts.method('getName')
    .setReturnType(ts.stringType)
    .addParameter(ts.parameter('format', ts.stringType)))
  .extends(ts.namedType('BaseModel'))
```

#### **Types**
```typescript
// Type declarations
ts.typeDeclaration('UserData', ts.objectType()
  .addProperty('name', ts.stringType))

// Unions
ts.unionType([ts.stringType, ts.numberType, ts.nullType])

// Intersections
ts.intersectionType(ts.namedType('A'), ts.namedType('B'))

// Conditionals
ts.conditionalType(ts.namedType('T'), ts.stringType, ts.numberType, ts.unknownType)

// Objects
ts.objectType()
  .addProperty('name', ts.stringType)
  .addProperty('age', ts.numberType)

// Arrays
ts.array(ts.stringType)  // string[]
ts.tuple([ts.stringType, ts.numberType])  // [string, number]

// Generics
const generic = ts.namedType('List').addGenericArgument(ts.stringType)
// List<string>
```

#### **Writer** (utility to build formatted strings)
```typescript
const writer = new Writer()
writer
  .write('const x = ')
  .writeLine('{')
  .withIndent(() => {
    writer.writeLine('foo: 123')
  })
  .writeLine('}')

writer.toString()  // Returns formatted code
```

#### **Property and Method**
```typescript
// Property
ts.property('name', ts.stringType)
  .optional()
  .readonly()
  .setDocComment(ts.docComment('User name'))

// Method
ts.method('getUserName')
  .setReturnType(ts.stringType)
  .addParameter(ts.parameter('id', ts.numberType))
  .addGenericParameter(ts.genericParameter('T').extends(ts.namedType('Base')))
```

#### **Primitive Types Available**
```typescript
ts.stringType, ts.numberType, ts.booleanType, ts.nullType,
ts.undefinedType, ts.bigintType, ts.unknownType, ts.anyType,
ts.voidType, ts.neverType, ts.thisType
```

#### **Imports**
```typescript
// Named imports
ts.moduleImport('path').named('join').named('resolve')

// Default import
ts.moduleImport('fs').default('fs')

// Namespace import
ts.moduleImport('@prisma/client').asNamespace('Prisma')

// Type-only imports
ts.moduleImport('types').named(ts.namedImport('User').typeOnly())
```

---

### 4. GeneratorOptions Type

**File:** `/packages/generator/src/configuration.ts`

This is what gets passed to your `onGenerate()` function:

```typescript
type GeneratorOptions = {
  // The generator configuration from schema.prisma
  generator: GeneratorConfig  // See below

  // Other generators in the schema
  otherGenerators: GeneratorConfig[]

  // Path to schema.prisma
  schemaPath: string

  // Full DMMF document (the parsed datamodel + types + mappings)
  dmmf: DMMF.Document

  // Database connection info
  datasources: DataSource[]  // { name, provider, activeProvider, schemas, sourceFilePath }

  // Raw schema.prisma as string
  datamodel: string

  // Version hash (implementation detail)
  version: string

  // Binary paths (internal engines)
  binaryPaths?: BinaryPaths

  // Suppress hints
  noHints?: boolean

  // Allow schema with no models
  allowNoModels?: boolean

  // Typed SQL outputs
  typedSql?: SqlQueryOutput[]
}

type GeneratorConfig = {
  name: string                    // From generator block name
  output: EnvValue | null         // { fromEnvVar, value } - the output directory
  provider: EnvValue              // The provider command/module
  config: {
    [key: string]: string | string[] | undefined  // Custom config options
  }
  binaryTargets: BinaryTargetsEnvValue[]
  previewFeatures: string[]
  sourceFilePath: string
}
```

**Accessing output path:**
```typescript
const outputPath = parseEnvValue(options.generator.output)  // String value
const outputDir = path.join(
  path.dirname(options.schemaPath),
  outputPath
)
```

---

### 5. Handler Interface

**File:** `/packages/generator-helper/src/generatorHandler.ts`

Your generator must implement this interface:

```typescript
interface Handler {
  onGenerate(options: GeneratorOptions): Promise<any>
  onManifest?(config: GeneratorConfig): GeneratorManifest | Promise<GeneratorManifest>
}

type GeneratorManifest = {
  prettyName?: string
  defaultOutput?: string
  denylists?: {
    models?: string[]
    fields?: string[]
  }
  requiresGenerators?: string[]  // Names of generators this depends on
  requiresEngines?: EngineType[]
  version?: string
  requiresEngineVersion?: string
}
```

**Usage:**
```typescript
import { generatorHandler } from '@prisma/generator-helper'

generatorHandler({
  onManifest: (config) => ({
    prettyName: 'My Custom Generator',
    defaultOutput: '../generated',
    version: '1.0.0'
  }),

  onGenerate: async (options) => {
    const outputDir = parseEnvValue(options.generator.output)
    // Generate files...
  }
})
```

---

### 6. Basic Generator Structure

**Reference Implementation:** `/packages/client-generator-ts/src/generator.ts`

Minimal structure:

```typescript
import { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import { generatorHandler } from '@prisma/generator-helper'
import { parseEnvValue } from '@prisma/internals'

class MyGenerator implements Generator {
  readonly name = 'my-generator'

  getManifest(config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      prettyName: 'My Generator',
      defaultOutput: './generated',
      version: '1.0.0'
    })
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = parseEnvValue(options.generator.output)

    // Access models:
    for (const model of options.dmmf.datamodel.models) {
      console.log(model.name)  // User, Post, etc.
      for (const field of model.fields) {
        console.log(`  ${field.name}: ${field.type}`)
      }
    }

    // Access enums:
    for (const enum_ of options.dmmf.datamodel.enums) {
      console.log(`enum ${enum_.name}`)
    }

    // Write files...
  }
}

const generator = new MyGenerator()

generatorHandler({
  async onManifest(config) {
    return generator.getManifest(config)
  },
  async onGenerate(options) {
    return generator.generate(options)
  }
})
```

---

### 7. Key Type Mappings Reference

**Prisma Schema → DMMF → TypeScript:**

| Prisma Type | DMMF field.type | TypeScript Type |
|---|---|---|
| `String` | `"String"` | `string` |
| `Int` | `"Int"` | `number` |
| `Float` | `"Float"` | `number` |
| `Boolean` | `"Boolean"` | `boolean` |
| `BigInt` | `"BigInt"` | `bigint \| number` |
| `Decimal` | `"Decimal"` | `Decimal \| DecimalJsLike \| number \| string` |
| `DateTime` | `"DateTime"` | `Date \| string` |
| `Json` | `"Json"` | `runtime.JsonValue` |
| `Bytes` | `"Bytes"` | `runtime.Bytes` |
| `MyEnum` | `"MyEnum"` | `$Enums.MyEnum` |
| `User` (relation) | `"User"` | User payload type |
| `Type[]` | field.isList=true | `Type[]` |
| `Type?` | field.isRequired=false | `Type \| null` |

---

### 8. Useful Utilities

From `/packages/internals/`:
- `parseEnvValue(envValue)` - Gets actual path from `{ fromEnvVar, value }`
- `isValidJsIdentifier(name)` - Checks if string is valid JS identifier

From `/packages/client-common/`:
- `keyBy(array, key)` - Indexes array by property
- `capitalize(str)` - Capitalizes string

From `/packages/ts-builders/`:
- `Writer` - For custom code formatting
- All type builders with fluent API

---

This gives you everything needed to create a generator that:
1. Reads the DMMF (all models, fields, enums, relations, defaults)
2. Generates TypeScript interfaces/types/classes with proper type mappings
3. Writes files to the configured output directory
4. Reports errors back to Prisma CLI

