import type { DMMF } from '@prisma/dmmf'

/**
 * Maps Prisma scalar type names to their TypeScript equivalents for REST transport.
 * DateTime is represented as an ISO-8601 string, Bytes as base64, Decimal simplified to number.
 */
const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Int: 'number',
  Float: 'number',
  Boolean: 'boolean',
  BigInt: 'bigint',
  Decimal: 'number',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
  ID: 'string',
  UUID: 'string',
}

/**
