import type { DMMF } from '@prisma/dmmf'

import { mapFieldType } from './type-mapper'

/**
 * Renders a TypeScript `interface` declaration for a Prisma model.
 *
 * Scalar and enum fields become required or optional properties matching their types.
 * Relation (object) fields are included as optional properties so the interface
 * can represent both flat responses and nested/eager-loaded ones.
 */
export function buildModelInterface(model: DMMF.Model): string {
  const lines: string[] = []

  if (model.documentation) {
    lines.push(`/** ${model.documentation} */`)
  }

  lines.push(`export interface ${model.name} {`)

  for (const field of model.fields) {
    if (field.documentation) {
      lines.push(`  /** ${field.documentation} */`)
    }

    const tsType = mapFieldType(field)
    // Relation fields are always optional in the interface because they are
    // only present when the REST endpoint includes them via expansion/include.
    const optional = field.kind === 'object' ? '?' : ''
    lines.push(`  ${field.name}${optional}: ${tsType}`)
  }

  lines.push(`}`)

  return lines.join('\n')
}

/**
 * Renders a TypeScript string-union `type` alias for a Prisma enum.
 *
 * Example output:
 *   export type Role = 'ADMIN' | 'USER'
 */
export function buildEnumType(dmmfEnum: DMMF.DatamodelEnum): string {
  const lines: string[] = []

  if (dmmfEnum.documentation) {
    lines.push(`/** ${dmmfEnum.documentation} */`)
  }

  if (dmmfEnum.values.length === 0) {
    lines.push(`export type ${dmmfEnum.name} = never`)
    return lines.join('\n')
  }

  const variants = dmmfEnum.values.map((v) => `'${v.name}'`).join(' | ')
  lines.push(`export type ${dmmfEnum.name} = ${variants}`)

  return lines.join('\n')
}

