import type { DMMF } from '@prisma/dmmf'

/**
 * Derives the REST route segment for a model.
 *
 * TODO: replace with a proper pluralisation library (e.g. `pluralize`) once
 * the dependency is approved, as the current naive approach does not handle
 * irregular plurals such as "Person" → "People".
 */
function toRouteName(modelName: string): string {
  const lower = modelName.toLowerCase()
  // Naive pluralisation: append 's', handle the common -s/-x/-z/-ch/-sh ending
  if (/(?:s|x|z|ch|sh)$/.test(lower)) {
    return `${lower}es`
  }
  return `${lower}s`
}

/**
 * Returns the DMMF field that serves as the primary key for the model.
 * Falls back to the first field when no `@id` annotation is present.
 */
function getIdField(model: DMMF.Model): DMMF.Field {
  return model.fields.find((f) => f.isId) ?? model.fields[0]
}

/**
 * Returns the TypeScript type string for the ID field.
 * Defaults to `string` for unsupported or missing ID types.
 */
function idTsType(idField: DMMF.Field): string {
  const map: Record<string, string> = {
    String: 'string',
    Int: 'number',
    BigInt: 'bigint',
  }
  return map[idField.type] ?? 'string'
}

/**
 * Renders a complete TypeScript class providing typed CRUD methods for a
 * single Prisma model. The class uses the `fetch` Web API and a configurable
 * base URL, making it usable in both Node.js (>=18) and browser environments.
 *
 * Generated methods:
 *   - `findMany`    GET  /<route>
 *   - `findUnique`  GET  /<route>/:id
 *   - `create`      POST /<route>
 *   - `update`      PUT  /<route>/:id
 *   - `delete`      DELETE /<route>/:id
 */
export function buildModelClient(model: DMMF.Model): string {
  const { name } = model
  const route = toRouteName(name)
  const idField = getIdField(model)
  const idType = idTsType(idField)

  return `import type { ${name} } from './types'

export class ${name}Client {
  #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl.replace(/\\/$/, '')
  }

  async findMany(params?: {
    where?: Partial<${name}>
    skip?: number
    take?: number
  }): Promise<${name}[]> {
    const url = new URL(\`\${this.#baseUrl}/${route}\`)
    if (params?.skip !== undefined) url.searchParams.set('skip', String(params.skip))
    if (params?.take !== undefined) url.searchParams.set('take', String(params.take))
    if (params?.where) {
      url.searchParams.set('where', JSON.stringify(params.where))
    }
    const res = await fetch(url, { method: 'GET' })
    if (!res.ok) throw new Error(\`HTTP \${res.status}: \${res.statusText}\`)
    return res.json() as Promise<${name}[]>
  }

  async findUnique(where: { ${idField.name}: ${idType} }): Promise<${name} | null> {
    const url = new URL(\`\${this.#baseUrl}/${route}/\${where.${idField.name}}\`)
    const res = await fetch(url, { method: 'GET' })
    if (res.status === 404) return null
    if (!res.ok) throw new Error(\`HTTP \${res.status}: \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async create(data: Omit<${name}, '${idField.name}'>): Promise<${name}> {
    const url = new URL(\`\${this.#baseUrl}/${route}\`)
    const res = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`HTTP \${res.status}: \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async update(
    where: { ${idField.name}: ${idType} },
    data: Partial<Omit<${name}, '${idField.name}'>>,
  ): Promise<${name}> {
    const url = new URL(\`\${this.#baseUrl}/${route}/\${where.${idField.name}}\`)
    const res = await fetch(url, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`HTTP \${res.status}: \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async delete(where: { ${idField.name}: ${idType} }): Promise<${name}> {
    const url = new URL(\`\${this.#baseUrl}/${route}/\${where.${idField.name}}\`)
    const res = await fetch(url, { method: 'DELETE' })
    if (!res.ok) throw new Error(\`HTTP \${res.status}: \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }
}
`
}

