import fs from 'node:fs/promises'
import path from 'node:path'

/** A map from filename to file content or a nested subdirectory map. */
export type FileMap = { [name: string]: string | FileMap }

/**
 * Recursively writes a `FileMap` to disk, creating directories as needed.
 * String values are written as UTF-8 text files; nested objects become
 * subdirectories and are processed recursively.
 */
export async function writeFiles(outputDir: string, files: FileMap): Promise<void> {
  await fs.mkdir(outputDir, { recursive: true })

  await Promise.all(
    Object.entries(files).map(async ([name, content]) => {
      const target = path.join(outputDir, name)
      if (typeof content === 'string') {
        await fs.writeFile(target, content, 'utf-8')
      } else {
        await writeFiles(target, content)
      }
    }),
  )
}

