import type { DMMF } from '@prisma/dmmf'

import { buildModelClient } from './model-client'
import { buildEnumType, buildModelInterface } from './model-interface'
import { type FileMap, writeFiles } from './write-files'

/**
 * Builds the barrel `index.ts` that re-exports every generated type and
 * client class, giving consumers a single import entry point.
 */
function buildIndex(models: readonly DMMF.Model[]): string {
  const lines = ["export * from './types'"]
  for (const model of models) {
    lines.push(`export { ${model.name}Client } from './${model.name.toLowerCase()}-client'`)
  }
  return lines.join('\n') + '\n'
}

/**
 * Orchestrates client generation for all models and enums in the schema.
 *
 * Output layout:
 *   <outputDir>/types.ts            — interfaces + enum unions for every model/enum
 *   <outputDir>/<model>-client.ts   — typed CRUD class for each model
 *   <outputDir>/index.ts            — barrel re-exporting all of the above
 */
export async function generateClient(options: { dmmf: DMMF.Document; outputDir: string }): Promise<void> {
  const { dmmf, outputDir } = options

  const enumSources = dmmf.datamodel.enums.map(buildEnumType)
  const interfaceSources = dmmf.datamodel.models.map(buildModelInterface)
  const typesSections = [...enumSources, ...interfaceSources]
  const typesSource = typesSections.join('\n\n') + '\n'

  const clientFiles: FileMap = {}
  for (const model of dmmf.datamodel.models) {
    clientFiles[`${model.name.toLowerCase()}-client.ts`] = buildModelClient(model)
  }

  const files: FileMap = {
    'types.ts': typesSource,
    'index.ts': buildIndex(dmmf.datamodel.models),
    ...clientFiles,
  }

  await writeFiles(outputDir, files)
}

