import type { DMMF } from '@prisma/dmmf'
import { describe, expect, it } from 'vitest'

import { mapFieldType } from '../type-mapper'

function field(overrides: Partial<DMMF.Field>): DMMF.Field {
  return {
    kind: 'scalar',
    name: 'field',
    type: 'String',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  } as DMMF.Field
}

describe('mapFieldType', () => {
  describe('scalar types', () => {
    it.each([
      ['String', 'string'],
      ['Int', 'number'],
      ['Float', 'number'],
      ['Boolean', 'boolean'],
      ['BigInt', 'bigint'],
      ['Decimal', 'number'],
      ['DateTime', 'string'],
      ['Json', 'unknown'],
      ['Bytes', 'string'],
      ['ID', 'string'],
      ['UUID', 'string'],
    ])('maps Prisma %s to TypeScript %s', (prismaType, expected) => {
      expect(mapFieldType(field({ type: prismaType }))).toBe(expected)
    })

    it('maps unknown scalar types to unknown', () => {
      expect(mapFieldType(field({ type: 'SomeNativeType', kind: 'unsupported' }))).toBe('unknown')
    })
  })

  describe('enum fields', () => {
    it('returns the enum name as the TypeScript type', () => {
      expect(mapFieldType(field({ kind: 'enum', type: 'Role' }))).toBe('Role')
    })
  })

  describe('relation (object) fields', () => {
    it('returns the related model name as the TypeScript type', () => {
      expect(mapFieldType(field({ kind: 'object', type: 'Post' }))).toBe('Post')
    })
  })

  describe('modifiers', () => {
    it('wraps list fields with []', () => {
      expect(mapFieldType(field({ isList: true }))).toBe('string[]')
    })

    it('adds | null for optional fields', () => {
      expect(mapFieldType(field({ isRequired: false }))).toBe('string | null')
    })

