    kind: 'scalar',
    name: 'field',
    type: 'String',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  } as DMMF.Field
}

