import type { DMMF } from '@prisma/dmmf'
import { describe, expect, it } from 'vitest'

import { buildEnumType, buildModelInterface } from '../model-interface'

function makeModel(overrides: Partial<DMMF.Model> & { fields: DMMF.Field[] }): DMMF.Model {
  return {
    name: 'User',
    dbName: null,
    schema: null,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
    ...overrides,
  } as DMMF.Model
}

function scalarField(name: string, type: string, opts: Partial<DMMF.Field> = {}): DMMF.Field {
  return {
    kind: 'scalar',
    name,
    type,
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...opts,
  } as DMMF.Field
}

describe('buildModelInterface', () => {
  it('generates a basic interface with required scalar fields', () => {
    const model = makeModel({
      name: 'User',
      fields: [scalarField('id', 'String', { isId: true }), scalarField('name', 'String'), scalarField('age', 'Int')],
    })

    expect(buildModelInterface(model)).toMatchInlineSnapshot(`
      "export interface User {
        id: string
        name: string
        age: number
      }"
    `)
  })

  it('generates optional properties for nullable fields', () => {
    const model = makeModel({
      name: 'Post',
      fields: [
        scalarField('id', 'String', { isId: true }),
        scalarField('bio', 'String', { isRequired: false }),
      ],
    })

    expect(buildModelInterface(model)).toMatchInlineSnapshot(`
      "export interface Post {
        id: string
        bio: string | null
      }"
    `)
  })

  it('marks relation fields as optional with ?', () => {
    const model = makeModel({
      name: 'Post',
      fields: [
        scalarField('id', 'String', { isId: true }),
        {
          kind: 'object',
          name: 'author',
          type: 'User',
          isRequired: true,
          isList: false,
          isUnique: false,
          isId: false,
          isReadOnly: false,
          hasDefaultValue: false,
          relationName: 'PostToUser',
          relationFromFields: ['authorId'],
          relationToFields: ['id'],
        } as DMMF.Field,
      ],
    })

    const output = buildModelInterface(model)
    expect(output).toContain('author?: User')
  })

  it('includes JSDoc comment when model has documentation', () => {
    const model = makeModel({
      name: 'User',
      documentation: 'A registered user',
      fields: [scalarField('id', 'String')],
    })

    expect(buildModelInterface(model)).toContain('/** A registered user */')
  })

  it('includes enum field with its type name', () => {
    const model = makeModel({
      name: 'User',
      fields: [
        scalarField('id', 'String', { isId: true }),
        { kind: 'enum', name: 'role', type: 'Role', isRequired: true, isList: false, isUnique: false, isId: false, isReadOnly: false, hasDefaultValue: false } as DMMF.Field,
      ],
    })

    expect(buildModelInterface(model)).toContain('role: Role')
  })
})

describe('buildEnumType', () => {
  it('generates a string union type', () => {
    const dmmfEnum: DMMF.DatamodelEnum = {
      name: 'Role',
      values: [{ name: 'ADMIN', dbName: null }, { name: 'USER', dbName: null }],
      dbName: null,
    }

    expect(buildEnumType(dmmfEnum)).toMatchInlineSnapshot(`"export type Role = 'ADMIN' | 'USER'"`)
  })

  it('generates never for an empty enum', () => {
    const dmmfEnum: DMMF.DatamodelEnum = { name: 'Empty', values: [], dbName: null }
    expect(buildEnumType(dmmfEnum)).toBe('export type Empty = never')
  })

  it('includes JSDoc comment when enum has documentation', () => {
    const dmmfEnum: DMMF.DatamodelEnum = {
      name: 'Status',
      values: [{ name: 'ACTIVE', dbName: null }],
      dbName: null,
      documentation: 'Account status',
    }

    expect(buildEnumType(dmmfEnum)).toContain('/** Account status */')
  })
})

