import type { DMMF } from '@prisma/dmmf'
import { describe, expect, it } from 'vitest'

import { buildModelClient } from '../model-client'

function makeModel(overrides: Partial<DMMF.Model> & { fields: DMMF.Field[] }): DMMF.Model {
  return {
    name: 'User',
    dbName: null,
    schema: null,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
    ...overrides,
  } as DMMF.Model
}

function scalarField(name: string, type: string, opts: Partial<DMMF.Field> = {}): DMMF.Field {
  return {
    kind: 'scalar',
    name,
    type,
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...opts,
  } as DMMF.Field
}

describe('buildModelClient', () => {
  it('generates a class with all five CRUD methods', () => {
    const model = makeModel({
      name: 'User',
      fields: [
        scalarField('id', 'String', { isId: true }),
        scalarField('name', 'String'),
      ],
    })

    const output = buildModelClient(model)

    expect(output).toContain('export class UserClient')
    expect(output).toContain('async findMany(')
    expect(output).toContain('async findUnique(')
    expect(output).toContain('async create(')
    expect(output).toContain('async update(')
    expect(output).toContain('async delete(')
  })

  it('imports the model interface from ./types', () => {
    const model = makeModel({
      name: 'Post',
      fields: [scalarField('id', 'Int', { isId: true })],
    })

    expect(buildModelClient(model)).toContain("import type { Post } from './types'")
  })

  it('uses the correct route name', () => {
    const userModel = makeModel({ name: 'User', fields: [scalarField('id', 'String', { isId: true })] })
    expect(buildModelClient(userModel)).toContain('/users')

    const postModel = makeModel({ name: 'Post', fields: [scalarField('id', 'String', { isId: true })] })
    expect(buildModelClient(postModel)).toContain('/posts')
  })

  it('applies -es suffix for models ending in s/x/z/ch/sh', () => {
    const model = makeModel({ name: 'Address', fields: [scalarField('id', 'String', { isId: true })] })
    expect(buildModelClient(model)).toContain('/addresses')
  })

  it('uses the @id field as the identifier in where clauses', () => {
    const model = makeModel({
      name: 'User',
      fields: [
        scalarField('uuid', 'String', { isId: true }),
        scalarField('email', 'String'),
      ],
    })

    const output = buildModelClient(model)
    expect(output).toContain('where: { uuid: string }')
    expect(output).toContain("Omit<User, 'uuid'>")
  })

  it('uses Int id type for numeric primary keys', () => {
    const model = makeModel({
      name: 'Post',
      fields: [scalarField('id', 'Int', { isId: true })],
    })

    expect(buildModelClient(model)).toContain('where: { id: number }')
  })

  it('falls back to the first field when no @id is present', () => {
    const model = makeModel({
      name: 'Tag',
      fields: [scalarField('slug', 'String'), scalarField('label', 'String')],
    })

    const output = buildModelClient(model)
    expect(output).toContain('where: { slug: string }')
  })

  it('strips trailing slashes from the base URL', () => {
    const model = makeModel({ name: 'User', fields: [scalarField('id', 'String', { isId: true })] })
    expect(buildModelClient(model)).toContain("this.#baseUrl = baseUrl.replace(/\\/$/, '')")
  })

  it('uses PUT for update and DELETE for delete', () => {
    const model = makeModel({ name: 'User', fields: [scalarField('id', 'String', { isId: true })] })
    const output = buildModelClient(model)
    expect(output).toContain("method: 'PUT'")
    expect(output).toContain("method: 'DELETE'")
  })
})

